const raw = $input.all()[0]?.json ?? {};
const trustedAllowedChatId = String(raw.allowedChatId || "").trim();
let payload = raw.query ?? raw;
let parseError = false;

if (typeof payload === "string") {
  try {
    payload = JSON.parse(payload);
  } catch (error) {
    payload = {};
    parseError = true;
  }
}

if (!payload || typeof payload !== "object" || Array.isArray(payload)) {
  payload = {};
  parseError = true;
}

let action = String(payload.action || payload.tool || payload.operation || "").trim();
if (!action) {
  const hasTargetUser = Boolean(payload.targetUserId || payload.allowedTargetUserId || payload.targetOpenId);
  action = hasTargetUser ? "read_okr" : (payload.chatId || payload.allowedChatId ? "list_chat_members" : "unknown");
}

const aliases = {
  read: "read_okr",
  get_okr: "read_okr",
  read_user_okr: "read_okr",
  analyze: "analyze_okr",
  analyse: "analyze_okr",
  okr_analysis: "analyze_okr",
  analyze_user_okr: "analyze_okr",
  list_members: "list_chat_members",
  list_chat_member: "list_chat_members",
  chat_members: "list_chat_members",
  group_members: "list_chat_members",
  summarize_group: "summarize_group_okrs",
  summarize_group_okr: "summarize_group_okrs",
  summarize_group_okrs: "summarize_group_okrs",
  group_summary: "summarize_group_okrs",
};
action = aliases[action] || action;

const supportedActions = ["read_okr", "list_chat_members", "analyze_okr", "summarize_group_okrs"];
const maxMembersRaw = Number(payload.maxMembers ?? 20);
const maxMembers = Number.isFinite(maxMembersRaw) ? Math.min(Math.max(Math.trunc(maxMembersRaw), 1), 20) : 20;
const rawChatId = String(payload.chatId || "").trim();
const requestedAllowedChatId = String(payload.allowedChatId || "").trim();
const chatAuthorizationError = action === "list_chat_members" && rawChatId
  ? "DIRECT_CHAT_ID_FORBIDDEN"
  : (action === "list_chat_members" && requestedAllowedChatId && requestedAllowedChatId !== trustedAllowedChatId
    ? "ALLOWED_CHAT_ID_MISMATCH"
    : "");

return [{
  json: {
    action: supportedActions.includes(action) ? action : "unknown_action",
    requestedAction: action,
    supportedActions,
    parseError,
    toolInput: payload,
    targetUserId: payload.targetUserId || payload.allowedTargetUserId || payload.targetOpenId || "",
    targetUserIdType: payload.targetUserIdType || payload.allowedTargetUserIdType || "open_id",
    targetDisplayName: payload.targetDisplayName || payload.allowedTargetDisplayName || "目标用户",
    chatId: chatAuthorizationError ? "" : trustedAllowedChatId,
    chatAuthorizationError,
    chatDisplayName: payload.chatDisplayName || "当前群",
    maxMembers,
    pageSize: maxMembers,
    pageToken: String(payload.pageToken ?? payload.page_token ?? "").trim(),
  },
}];

const input = $input.all()[0]?.json ?? {};
const request = $('Normalize').all()[0]?.json ?? {};

function asBoolean(value) {
  if (typeof value === 'boolean') return value;
  if (typeof value === 'string') return value.toLowerCase() === 'true';
  return Boolean(value);
}

function finish(output, ok = false, extra = {}, errorCode = 'LIST_CHAT_MEMBERS_FAILED') {
  const members = Array.isArray(extra.members) ? extra.members : [];
  const hasMore = asBoolean(extra.hasMore ?? false);
  const nextPageToken = String(extra.nextPageToken ?? '').trim();
  return [{
    json: {
      ok,
      action: 'list_chat_members',
      version: 'v1',
      data: { members, hasMore, nextPageToken },
      error: ok ? null : { code: errorCode, message: output, retryable: false },
      meta: {
        chatId: request.chatId || extra.chatId || '',
        chatDisplayName: request.chatDisplayName || extra.chatDisplayName || '',
        maxMembers: request.maxMembers || 20,
        truncated: hasMore,
      },
      members,
      hasMore,
      nextPageToken,
      output,
      chatMemberToolOk: ok,
      ...extra,
    },
  }];
}

if (request.chatAuthorizationError) {
  return finish('list_chat_members 群授权校验失败。请在目标群中发起请求。', false, {}, request.chatAuthorizationError);
}

if (!request.chatId || request.parseError) {
  return finish('list_chat_members 缺少有效 allowedChatId。请在目标群中发起请求。', false, {}, request.parseError ? 'INVALID_TOOL_INPUT' : 'MISSING_ALLOWED_CHAT_ID');
}

if (input.error) {
  const detail = typeof input.error === 'string' ? input.error : (input.error.message || JSON.stringify(input.error));
  return finish('读取群成员失败：' + detail, false, {
    chatId: request.chatId,
    chatDisplayName: request.chatDisplayName,
  }, 'LIST_CHAT_MEMBERS_HTTP_ERROR');
}

if (input.code && input.code !== 0) {
  return finish('读取群成员失败：' + (input.msg || JSON.stringify(input)), false, {
    chatId: request.chatId,
    chatDisplayName: request.chatDisplayName,
  }, 'LIST_CHAT_MEMBERS_API_ERROR');
}

const rawMembers = input.items ?? input.members ?? input.data?.items ?? input.data?.members ?? [];
const hasMore = asBoolean(input.has_more ?? input.data?.has_more ?? input.hasMore ?? input.data?.hasMore);
const nextPageToken = String(input.page_token ?? input.data?.page_token ?? input.nextPageToken ?? input.data?.nextPageToken ?? '').trim();

if (!Array.isArray(rawMembers) || rawMembers.length === 0) {
  return finish('没有读取到群成员。请确认机器人在该群内，并且应用已开通 im:chat.members:read 权限。', false, {
    chatId: request.chatId,
    chatDisplayName: request.chatDisplayName,
    hasMore,
    nextPageToken,
  }, 'NO_CHAT_MEMBERS');
}

function memberId(member) {
  const id = member.member_id ?? member.open_id ?? member.user_id ?? member.id?.open_id ?? member.id?.user_id ?? '';
  return String(id || '').trim();
}

function memberName(member, id) {
  return String(member.name ?? member.display_name ?? member.member_name ?? member.nickname ?? id).trim();
}

const members = [];
const seen = new Set();
for (const member of rawMembers) {
  const id = memberId(member);
  if (!id || seen.has(id)) continue;
  const type = String(member.member_type ?? member.type ?? '').toLowerCase();
  if (type.includes('bot')) continue;
  seen.add(id);
  members.push({
    targetUserId: id,
    targetUserIdType: 'open_id',
    targetDisplayName: memberName(member, id),
  });
  if (members.length >= request.maxMembers) break;
}

const lines = [
  '已读取' + request.chatDisplayName + '成员 ' + members.length + ' 人。',
  hasMore ? '还有更多成员；下一页请继续传入 pageToken=' + nextPageToken + '。' : '',
  '接下来请逐个读取 members 数组中的用户 OKR。',
].filter(Boolean);

return finish(lines.join('\n'), true, {
  chatId: request.chatId,
  chatDisplayName: request.chatDisplayName,
  members,
  hasMore,
  nextPageToken,
});

const input = $input.all()[0]?.json ?? {};
const request = $('Normalize').all()[0]?.json ?? {};
const targetName = request.targetDisplayName || '目标用户';
const targetPossessive = targetName === '你' ? '你的' : targetName + '的';

function finish(output, ok = false) {
  return [{ json: { output, okrToolOk: ok, targetDisplayName: targetName } }];
}

if (!request.targetUserId || request.parseError) {
  return finish('read_okr 缺少有效 targetUserId。请传入目标用户 ID。');
}

if (input.error) {
  const detail = typeof input.error === 'string' ? input.error : (input.error.message || JSON.stringify(input.error));
  return finish('读取' + targetPossessive + ' OKR 周期失败：' + detail);
}

if (input.code && input.code !== 0) {
  return finish('读取' + targetPossessive + ' OKR 周期失败：' + (input.msg || JSON.stringify(input)));
}

const cycles = input.cycles ?? input.items ?? input.data?.cycles ?? input.data?.items ?? [];
if (!Array.isArray(cycles) || cycles.length === 0) {
  return finish('没有找到' + targetPossessive + ' OKR 周期。');
}

function asTime(value) {
  if (!value) return NaN;
  const raw = String(value).trim();
  const numeric = Number(raw);
  if (Number.isFinite(numeric)) return numeric < 1000000000000 ? numeric * 1000 : numeric;
  return new Date(raw.replace(' ', 'T')).getTime();
}

const now = Date.now();
const activeStatuses = new Set(['', '0', '1', 'default', 'normal']);
const invisibleStatuses = new Set(['2', '3', 'invalid', 'hidden']);
const requestedCycleId = String(request.toolInput?.cycleId ?? request.toolInput?.cycle_id ?? '').trim();
const statusValue = (cycle) => String(cycle.cycle_status ?? '').toLowerCase();
const currentCycles = cycles.filter((cycle) => {
  const start = asTime(cycle.start_time);
  const end = asTime(cycle.end_time);
  return Number.isFinite(start) && Number.isFinite(end) && start <= now && end >= now && activeStatuses.has(statusValue(cycle));
});
const visibleCycles = cycles.filter((cycle) => !invisibleStatuses.has(statusValue(cycle)));
const candidates = currentCycles.length ? currentCycles : (visibleCycles.length ? visibleCycles : cycles);
const selected = requestedCycleId
  ? cycles.find((cycle) => String(cycle.id ?? '').trim() === requestedCycleId)
  : [...candidates].sort((a, b) => asTime(b.start_time) - asTime(a.start_time))[0];
const selectedId = String(selected?.id ?? '').trim();
if (!selectedId) {
  return finish('读取' + targetPossessive + ' OKR 周期失败：当前周期缺少 cycleId。');
}

function formatDate(value) {
  const time = asTime(value);
  if (!Number.isFinite(time)) return '';
  return new Intl.DateTimeFormat('zh-CN', { timeZone: 'Asia/Shanghai', year: 'numeric', month: '2-digit', day: '2-digit' }).format(new Date(time)).replace(/\//g, '-');
}

const start = formatDate(selected.start_time);
const end = formatDate(selected.end_time);

return [{
  json: {
    cycleId: selectedId,
    cycleLabel: start && end ? start + ' - ' + end : selectedId,
    cycleStartDate: start,
    cycleEndDate: end,
    targetUserId: request.targetUserId,
    targetUserIdType: request.targetUserIdType || 'open_id',
    targetDisplayName: targetName,
    okrToolOk: true,
  },
}];

const input = $input.all()[0]?.json ?? {};
const selected = $('Select cycle').all()[0]?.json ?? {};

if (!selected.okrToolOk) {
  return [{ json: { ...selected, noObjectives: true } }];
}

if (input.error) {
  const detail = typeof input.error === 'string' ? input.error : (input.error.message || JSON.stringify(input.error));
  return [{ json: { ...selected, noObjectives: true, output: '读取目标列表失败：' + detail } }];
}

if (input.code && input.code !== 0) {
  return [{ json: { ...selected, noObjectives: true, output: '读取目标列表失败：' + (input.msg || JSON.stringify(input)) } }];
}

const objectives = input.objectives ?? input.items ?? input.data?.objectives ?? input.data?.items ?? [];
if (!Array.isArray(objectives) || objectives.length === 0) {
  return [{ json: { ...selected, noObjectives: true, objectives: [] } }];
}

const expanded = objectives.map((objective) => ({
  json: {
    ...selected,
    objective,
    objectiveId: String(objective.id ?? '').trim(),
    noObjectives: false,
  },
}));

if (expanded.some((item) => !item.json.objectiveId)) {
  return [{ json: { ...selected, noObjectives: true, output: '读取目标列表失败：目标缺少 objectiveId。' } }];
}

return expanded;

const krResponses = $input.all();
const expanded = $('Expand objectives').all();
const request = $('Normalize').all()[0]?.json ?? {};
const firstExpanded = expanded[0]?.json ?? {};
const targetName = firstExpanded.targetDisplayName || request.targetDisplayName || '目标用户';
const targetPossessive = targetName === '你' ? '你的' : targetName + '的';

function textFromContent(value) {
  if (!value) return '';
  if (typeof value === 'string') {
    const trimmed = value.trim();
    if (!trimmed) return '';
    try { return textFromContent(JSON.parse(trimmed)); } catch (error) { return trimmed; }
  }
  if (Array.isArray(value)) return value.map(textFromContent).filter(Boolean).join('');
  if (typeof value === 'object') {
    if (typeof value.text === 'string') return value.text.trim();
    if (typeof value.text_run?.text === 'string') return value.text_run.text.trim();
    if (typeof value.docs_link?.title === 'string') return value.docs_link.title.trim();
    if (Array.isArray(value.blocks)) return value.blocks.map(textFromContent).filter(Boolean).join('\n');
    if (Array.isArray(value.elements)) return value.elements.map(textFromContent).filter(Boolean).join('');
    if (value.paragraph?.elements) return textFromContent(value.paragraph.elements);
    if (value.content) return textFromContent(value.content);
  }
  return '';
}

function numericScore(score) {
  const numeric = Number(score);
  return Number.isFinite(numeric) ? numeric : null;
}

function scoreText(score) {
  const numeric = numericScore(score);
  if (numeric === null) return '';
  const percent = numeric <= 1 ? Math.round(numeric * 100) : Math.round(numeric);
  return '（' + percent + '%）';
}

function normalizedTarget() {
  return {
    userId: String(request.targetUserId || firstExpanded.targetUserId || '').trim(),
    userIdType: String(request.targetUserIdType || firstExpanded.targetUserIdType || 'open_id').trim(),
    displayName: targetName,
  };
}

function normalizedCycle() {
  return {
    id: String(firstExpanded.cycleId || '').trim(),
    label: String(firstExpanded.cycleLabel || '').trim(),
    startDate: String(firstExpanded.cycleStartDate || '').trim(),
    endDate: String(firstExpanded.cycleEndDate || '').trim(),
  };
}

function finish(output, ok = false, extra = {}, errorCode = 'READ_OKR_FAILED') {
  const data = extra.data || {};
  return [{
    json: {
      ok,
      action: 'read_okr',
      version: 'v2',
      data,
      error: ok ? null : { code: errorCode, message: output, retryable: false },
      meta: {
        target: normalizedTarget(),
        targetDisplayName: targetName,
        cycle: normalizedCycle(),
        cycleId: firstExpanded.cycleId || '',
        cycleLabel: firstExpanded.cycleLabel || '',
        truncated: false,
      },
      output,
      okrToolOk: ok,
      targetDisplayName: targetName,
      cycleLabel: firstExpanded.cycleLabel,
      ...extra,
    },
  }];
}

function emptyData() {
  return {
    target: normalizedTarget(),
    cycle: normalizedCycle(),
    objectives: [],
    counts: { objectives: 0, keyResults: 0 },
  };
}

if (firstExpanded.output && firstExpanded.noObjectives) {
  const code = firstExpanded.output.includes('缺少 objectiveId') ? 'MISSING_OBJECTIVE_ID' : 'READ_OKR_OBJECTIVES_FAILED';
  return finish(firstExpanded.output, false, { data: emptyData() }, code);
}

if (firstExpanded.noObjectives) {
  return finish('读取结果：' + targetPossessive + ' ' + (firstExpanded.cycleLabel || '当前周期') + ' OKR\n这个周期下没有目标。', true, { data: emptyData() });
}

function objectiveLabel(expandedItem, index) {
  const objective = expandedItem.json.objective ?? {};
  const title = textFromContent(objective.content) || '(未命名目标)';
  return '第 ' + String(index + 1) + ' 个目标 ' + title;
}

for (const [index, expandedItem] of expanded.entries()) {
  const objective = expandedItem.json.objective;
  if (!objective) continue;
  const response = krResponses[index]?.json ?? {};
  const label = objectiveLabel(expandedItem, index);
  if (response.error) {
    const detail = typeof response.error === 'string' ? response.error : (response.error.message || JSON.stringify(response.error));
    const output = '读取' + targetPossessive + ' OKR 失败：' + label + ' 的关键结果读取失败：' + detail;
    return finish(output, false, { data: { ...emptyData(), failedObjectiveIndex: index + 1, failedObjectiveId: expandedItem.json.objectiveId || '', failedObjectiveTitle: textFromContent(objective.content) || '(未命名目标)' } }, 'READ_OKR_KEY_RESULTS_HTTP_ERROR');
  }
  const hasResponseCode = response.code !== undefined && response.code !== null && response.code !== '';
  const responseCode = Number(response.code);
  if (hasResponseCode && (!Number.isFinite(responseCode) || responseCode !== 0)) {
    const detail = response.msg || JSON.stringify(response);
    const output = '读取' + targetPossessive + ' OKR 失败：' + label + ' 的关键结果读取失败：' + detail;
    return finish(output, false, { data: { ...emptyData(), failedObjectiveIndex: index + 1, failedObjectiveId: expandedItem.json.objectiveId || '', failedObjectiveTitle: textFromContent(objective.content) || '(未命名目标)' } }, 'READ_OKR_KEY_RESULTS_API_ERROR');
  }
}

const objectives = [];
const lines = ['读取结果：' + targetPossessive + ' ' + (firstExpanded.cycleLabel || '当前周期') + ' OKR'];
let keyResultCount = 0;

for (const [index, expandedItem] of expanded.entries()) {
  const objective = expandedItem.json.objective;
  if (!objective) continue;
  const response = krResponses[index]?.json ?? {};
  const rawKeyResults = response.key_results ?? response.items ?? response.data?.key_results ?? response.data?.items ?? [];
  const keyResults = Array.isArray(rawKeyResults)
    ? [...rawKeyResults].sort((a, b) => Number(a.position ?? 0) - Number(b.position ?? 0)).map((kr) => ({
        id: String(kr.id ?? kr.key_result_id ?? '').trim(),
        title: textFromContent(kr.content) || '(未命名关键结果)',
        score: numericScore(kr.score),
        progress: String(kr.progress ?? kr.progress_rate ?? kr.metric?.current_value ?? '').trim(),
        status: String(kr.status ?? kr.progress_status ?? kr.state ?? '').trim(),
        position: Number.isFinite(Number(kr.position)) ? Number(kr.position) : null,
      }))
    : [];
  keyResultCount += keyResults.length;
  const title = textFromContent(objective.content) || '(未命名目标)';
  objectives.push({
    id: String(objective.id ?? expandedItem.json.objectiveId ?? '').trim(),
    title,
    score: numericScore(objective.score),
    keyResults,
  });
  lines.push(String(index + 1) + '. O: ' + title + scoreText(objective.score));
  for (const kr of keyResults) {
    lines.push('   - KR: ' + kr.title + scoreText(kr.score));
  }
}

const data = {
  target: normalizedTarget(),
  cycle: normalizedCycle(),
  objectives,
  counts: {
    objectives: objectives.length,
    keyResults: keyResultCount,
  },
};

return finish(lines.join('\n'), true, { data });

const input = $input.all()[0]?.json ?? {};
const request = $('Normalize').all()[0]?.json ?? {};
const targetName = request.targetDisplayName || input.targetDisplayName || '目标用户';
const targetPossessive = targetName === '你' ? '你的' : targetName + '的';

let code = 'MISSING_REQUIRED_FIELD';
let message = input.output || '';

if (request.parseError) {
  code = 'INVALID_TOOL_INPUT';
  message = 'okr_tools 参数不是有效 JSON。请传入 JSON 字符串。';
} else if (!request.targetUserId) {
  code = 'MISSING_TARGET_USER_ID';
  message = 'read_okr 缺少有效 targetUserId。请传入目标用户 ID。';
} else if (!input.cycleId) {
  code = input.output ? 'READ_OKR_CYCLE_FAILED' : 'MISSING_CYCLE_ID';
  message = input.output || '读取' + targetPossessive + ' OKR 失败：没有可用的 cycleId。';
} else if (!input.objectiveId) {
  code = 'MISSING_OBJECTIVE_ID';
  message = input.output || '读取' + targetPossessive + ' OKR 失败：目标缺少 objectiveId。';
}

return [{
  json: {
    ok: false,
    action: 'read_okr',
    version: 'v2',
    output: message,
    error: { code, message, retryable: false },
    data: {
      target: { userId: request.targetUserId || '', userIdType: request.targetUserIdType || 'open_id', displayName: targetName },
      cycle: { id: input.cycleId || '', label: input.cycleLabel || '' },
      objectives: [],
      counts: { objectives: 0, keyResults: 0 },
    },
    meta: {
      targetUserId: request.targetUserId || '',
      targetUserIdType: request.targetUserIdType || 'open_id',
      targetDisplayName: targetName,
      cycleId: input.cycleId || '',
      objectiveId: input.objectiveId || '',
    },
    okrToolOk: false,
    targetDisplayName: targetName,
    cycleLabel: input.cycleLabel || '',
  },
}];

const input = $input.all()[0]?.json ?? {};
const action = input.requestedAction || input.action || "";
const supported = Array.isArray(input.supportedActions) ? input.supportedActions.join(", ") : "read_okr, list_chat_members, analyze_okr, summarize_group_okrs";
const output = input.parseError
  ? "okr_tools 参数不是有效 JSON。请传入 JSON 字符串。"
  : "okr_tools 不支持 action：" + (action || "(空)") + "。当前支持：" + supported;
return [{
  json: {
    ok: false,
    action: input.action || "unknown_action",
    version: 'v1',
    output,
    error: {
      code: input.parseError ? "INVALID_TOOL_INPUT" : "UNKNOWN_ACTION",
      message: output,
      retryable: false,
    },
    data: {},
    meta: { supportedActions: input.supportedActions || [] },
  },
}];

const request = $input.all()[0]?.json ?? {};
const payload = request.toolInput ?? {};

function unwrap(input) {
  if (!input || typeof input !== 'object') return null;
  if (input.data?.objectives) return input.data;
  if (Array.isArray(input.objectives)) return input;
  if (input.okrResult?.data?.objectives) return input.okrResult.data;
  if (input.okrData?.objectives) return input.okrData;
  if (input.result?.data?.objectives) return input.result.data;
  return null;
}

const data = unwrap(payload) || unwrap(payload.data) || unwrap(payload.okrResult) || unwrap(payload.okrData);

function finish(output, ok = false, extra = {}, errorCode = 'ANALYZE_OKR_FAILED') {
  return [{
    json: {
      ok,
      action: 'analyze_okr',
      version: 'v1',
      data: extra.data || {},
      error: ok ? null : { code: errorCode, message: output, retryable: false },
      meta: {
        target: data?.target || null,
        cycle: data?.cycle || null,
        truncated: false,
      },
      output,
      ...extra,
    },
  }];
}

if (request.parseError) {
  return finish('analyze_okr 参数不是有效 JSON。', false, {}, 'INVALID_TOOL_INPUT');
}

if (!data || !Array.isArray(data.objectives)) {
  return finish('analyze_okr 需要传入 read_okr 返回的结构化 data 或 okrResult。', false, {}, 'MISSING_OKR_DATA');
}

function asPercent(score) {
  const n = Number(score);
  if (!Number.isFinite(n)) return null;
  return n <= 1 ? Math.round(n * 100) : Math.round(n);
}

const objectives = data.objectives;
const risks = [];
const suggestions = [];
const missingSignals = [];
let krCount = 0;
let lowKrCount = 0;

if (!objectives.length) {
  risks.push({ level: 'high', type: 'no_objectives', message: '当前周期没有读取到 Objective。' });
  suggestions.push('先补齐 1-3 个本周期最关键的 Objective，再为每个 Objective 绑定可量化 KR。');
}

if (objectives.length > 5) {
  risks.push({ level: 'medium', type: 'too_many_objectives', message: 'Objective 数量偏多，可能分散投入。' });
  suggestions.push('把目标收敛到最关键的 3-5 个，并把执行类事项下沉到 KR 或任务。');
}

for (const [index, objective] of objectives.entries()) {
  const title = String(objective.title || '(未命名目标)');
  const objectiveScore = asPercent(objective.score);
  const keyResults = Array.isArray(objective.keyResults) ? objective.keyResults : [];
  if (objectiveScore !== null && objectiveScore < 50) {
    risks.push({ level: 'high', type: 'low_objective_score', objective: title, score: objectiveScore, message: '目标分数低于 50%。' });
  } else if (objectiveScore !== null && objectiveScore < 70) {
    risks.push({ level: 'medium', type: 'watch_objective_score', objective: title, score: objectiveScore, message: '目标分数低于 70%，建议关注推进风险。' });
  }
  if (!keyResults.length) {
    risks.push({ level: 'high', type: 'objective_without_key_results', objective: title, message: 'Objective 没有关联 KR。' });
  }
  if (title.length < 8 || /(提升|优化|完善|加强|推进|支持|保障)$/.test(title)) {
    missingSignals.push({ type: 'vague_objective', objective: title, message: '目标表述可能偏动作化或不够结果导向。' });
  }
  for (const kr of keyResults) {
    krCount += 1;
    const krTitle = String(kr.title || '(未命名关键结果)');
    const krScore = asPercent(kr.score);
    if (krScore === null) {
      missingSignals.push({ type: 'missing_kr_score', objective: title, keyResult: krTitle, message: 'KR 缺少可读分数。' });
    } else if (krScore < 50) {
      lowKrCount += 1;
      risks.push({ level: 'high', type: 'low_kr_score', objective: title, keyResult: krTitle, score: krScore, message: 'KR 分数低于 50%。' });
    }
    if (!/\d|%|增长|降低|完成|上线|交付|覆盖|转化|收入|成本|时长|数量|率/.test(krTitle)) {
      missingSignals.push({ type: 'weak_measurement', objective: title, keyResult: krTitle, message: 'KR 可能缺少明确量化口径。' });
    }
  }
  if (index < 3 && keyResults.length > 5) {
    missingSignals.push({ type: 'too_many_key_results', objective: title, message: '单个 Objective 的 KR 数量偏多。' });
  }
}

if (lowKrCount > 0) suggestions.push('优先拆解低于 50% 的 KR：明确阻塞、责任人、下周最小推进动作。');
if (missingSignals.some((item) => item.type === 'weak_measurement')) suggestions.push('把偏描述性的 KR 改成带数字、时间点或验收口径的结果指标。');
if (risks.some((item) => item.type === 'objective_without_key_results')) suggestions.push('没有 KR 的 Objective 需要补充可验证结果，否则后续无法判断完成度。');
if (!suggestions.length) suggestions.push('整体结构可读，建议继续保持每周更新 KR 分数和阻塞说明。');

const cappedRisks = risks.slice(0, 8);
const cappedMissing = missingSignals.slice(0, 8);
const cappedSuggestions = suggestions.slice(0, 3);
const targetName = data.target?.displayName || request.targetDisplayName || '目标用户';
const summary = targetName + '当前周期共有 ' + objectives.length + ' 个 Objective、' + krCount + ' 个 KR；识别到 ' + cappedRisks.length + ' 个主要风险信号。';
const lines = [summary];
if (cappedRisks.length) {
  lines.push('风险：');
  for (const risk of cappedRisks.slice(0, 5)) lines.push('- ' + risk.message + (risk.objective ? ' ' + risk.objective : ''));
}
lines.push('建议：');
for (const suggestion of cappedSuggestions) lines.push('- ' + suggestion);

return finish(lines.join('\n'), true, {
  data: {
    summary,
    risks: cappedRisks,
    suggestions: cappedSuggestions,
    missingSignals: cappedMissing,
    counts: { objectives: objectives.length, keyResults: krCount },
  },
});

const request = $input.all()[0]?.json ?? {};
const payload = request.toolInput ?? {};

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

const rawResults = asArray(payload.okrResults)
  .concat(asArray(payload.results))
  .concat(asArray(payload.groupResults))
  .filter(Boolean);

function unwrap(result) {
  if (!result || typeof result !== 'object') return { ok: false, data: null, error: { code: 'INVALID_RESULT', message: '结果不是对象' } };
  if (result.data?.objectives) return { ok: result.ok !== false, data: result.data, error: result.error || null };
  if (Array.isArray(result.objectives)) return { ok: true, data: result, error: null };
  return { ok: false, data: null, error: result.error || { code: 'MISSING_OKR_DATA', message: '缺少结构化 OKR data' } };
}

function finish(output, ok = false, extra = {}, errorCode = 'SUMMARIZE_GROUP_OKRS_FAILED') {
  return [{
    json: {
      ok,
      action: 'summarize_group_okrs',
      version: 'v1',
      data: extra.data || {},
      error: ok ? null : { code: errorCode, message: output, retryable: false },
      meta: {
        chatDisplayName: request.chatDisplayName || payload.chatDisplayName || '',
        partial: Boolean(extra.data?.partial),
        truncated: Boolean(extra.data?.truncated),
      },
      output,
      ...extra,
    },
  }];
}

if (request.parseError) {
  return finish('summarize_group_okrs 参数不是有效 JSON。', false, {}, 'INVALID_TOOL_INPUT');
}

if (!rawResults.length) {
  return finish('summarize_group_okrs 需要传入 okrResults 数组。', false, {}, 'MISSING_GROUP_OKR_RESULTS');
}

function percent(score) {
  const n = Number(score);
  if (!Number.isFinite(n)) return null;
  return n <= 1 ? Math.round(n * 100) : Math.round(n);
}

const members = [];
const failedTargets = [];
const lowObjectives = [];
const lowKeyResults = [];
const uncovered = [];
let objectiveCount = 0;
let keyResultCount = 0;

for (const result of rawResults) {
  const unwrapped = unwrap(result);
  if (!unwrapped.ok || !unwrapped.data) {
    failedTargets.push({ target: result?.meta?.target || result?.data?.target || null, error: unwrapped.error });
    continue;
  }
  const data = unwrapped.data;
  const target = data.target || result.meta?.target || { displayName: result.targetDisplayName || '未知成员' };
  const objectives = asArray(data.objectives);
  members.push({ target, objectiveCount: objectives.length, keyResultCount: objectives.reduce((sum, objective) => sum + asArray(objective.keyResults).length, 0) });
  if (!objectives.length) uncovered.push({ target, reason: 'no_objectives' });
  for (const objective of objectives) {
    objectiveCount += 1;
    const objectiveScore = percent(objective.score);
    if (objectiveScore !== null && objectiveScore < 60) lowObjectives.push({ target, title: objective.title, score: objectiveScore });
    const keyResults = asArray(objective.keyResults);
    if (!keyResults.length) uncovered.push({ target, objective: objective.title, reason: 'no_key_results' });
    for (const kr of keyResults) {
      keyResultCount += 1;
      const krScore = percent(kr.score);
      if (krScore !== null && krScore < 60) lowKeyResults.push({ target, objective: objective.title, title: kr.title, score: krScore });
    }
  }
}

const partial = failedTargets.length > 0 || Boolean(payload.hasMore);
const risks = [
  ...lowObjectives.slice(0, 8).map((item) => ({ type: 'low_objective_score', level: item.score < 50 ? 'high' : 'medium', ...item })),
  ...lowKeyResults.slice(0, 8).map((item) => ({ type: 'low_kr_score', level: item.score < 50 ? 'high' : 'medium', ...item })),
  ...uncovered.slice(0, 8).map((item) => ({ type: item.reason, level: 'medium', ...item })),
].slice(0, 12);

const suggestions = [];
if (lowObjectives.length || lowKeyResults.length) suggestions.push('先集中处理低于 60% 的目标/KR，按负责人确认阻塞与下一步。');
if (uncovered.length) suggestions.push('补齐没有 KR 或没有目标的成员/方向，避免团队目标无法验收。');
if (partial) suggestions.push('本次汇总存在部分失败或分页未读完，结论需要标注为部分结果。');
if (!suggestions.length) suggestions.push('团队 OKR 结构整体完整，建议继续按周更新分数并同步阻塞。');

const chatName = request.chatDisplayName || payload.chatDisplayName || '当前团队';
const summary = chatName + '共汇总 ' + members.length + ' 人、' + objectiveCount + ' 个 Objective、' + keyResultCount + ' 个 KR；主要风险 ' + risks.length + ' 个。';
const lines = [summary];
if (partial) lines.push('注意：本次是部分结果。');
if (risks.length) {
  lines.push('风险：');
  for (const risk of risks.slice(0, 5)) {
    const owner = risk.target?.displayName || risk.target?.userId || '未知成员';
    lines.push('- ' + owner + '：' + (risk.title || risk.objective || risk.reason) + (risk.score !== undefined ? '（' + risk.score + '%）' : ''));
  }
}
lines.push('建议：');
for (const suggestion of suggestions.slice(0, 3)) lines.push('- ' + suggestion);

return finish(lines.join('\n'), true, {
  data: {
    summary,
    members,
    risks,
    failedTargets,
    uncovered,
    suggestions: suggestions.slice(0, 3),
    partial,
    truncated: Boolean(payload.hasMore),
    counts: { members: members.length, objectives: objectiveCount, keyResults: keyResultCount, failedTargets: failedTargets.length },
  },
});
